@Component("batchOpertValidator")
public class BatchOpertValidator implements Validator {

	/*
	 * (non-Javadoc)
	 * @see org.springframework.validation.Validator#supports(java.lang.Class)
	 */
	@Override
	public boolean supports(Class<?> clazz) {
		return BatchOpert.class.isAssignableFrom(clazz);
	}

	/*
	 * (non-Javadoc)
	 * @see org.springframework.validation.Validator#validate(java.lang.Object, org.springframework.validation.Errors)
	 */
	@Override
	public void validate(Object obj, Errors errors) {
		// 배치프로그램으로 지정된 값이 파일로 존재하는지 검사한다.
		BatchOpert batchOpert = (BatchOpert) obj;
		//KISA 보안약점 조치 (2018-10-29, 윤창원)
		String filePath = EgovProperties.getProperty("SHELL.batchShellFolder") + batchOpert.getBatchProgrm();
		File file = new File(EgovWebUtil.filePathBlackList(filePath));
		try {
			if (!file.exists()) {
				errors.rejectValue("batchProgrm", "errors.batchProgrm", new Object[] { batchOpert.getBatchProgrm() }, "배치프로그램 {0}이  존재하지 않습니다.");
				return;
			}
			if (!file.isFile()) {
				errors.rejectValue("batchProgrm", "errors.batchProgrm", new Object[] { batchOpert.getBatchProgrm() }, "배치프로그램 {0}이 파일이 아닙니다.");
				return;
			}
		} catch (SecurityException se) {
			errors.rejectValue("batchProgrm", "errors.batchProgrm", new Object[] { batchOpert.getBatchProgrm() }, " 배치프로그램 {0}에 접근할 수 없습니다. 파일접근권한을 확인하세요.");
		}

	}

}

/**
 * 배치작업을 등록한다.
 * @return 리턴URL
 *
 * @param batchOpert 등록대상 배치작업model
 * @param bindingResult	BindingResult
 * @param model			ModelMap
 * @param RedirectAttributes redirectAttributes
 * @exception Exception Exception
 */
@RequestMapping("/sym/bat/addBatchOpert.do")
public String insertBatchOpert(@ModelAttribute("searchVO") BatchOpert searchVO,
		@Valid @ModelAttribute("batchOpert") BatchOpert batchOpert, BindingResult bindingResult,
		ModelMap model, RedirectAttributes redirectAttributes) throws Exception {

	// 0. Spring Security 사용자권한 처리
	Boolean isAuthenticated = EgovUserDetailsHelper.isAuthenticated();
	if (!isAuthenticated) {
		redirectAttributes.addAttribute("message", egovMessageSource.getMessage("fail.common.login"));
		return "redirect:/uat/uia/egovLoginUsr.do";
	}

	//로그인 객체 선언
	LoginVO loginVO = (LoginVO) EgovUserDetailsHelper.getAuthenticatedUser();

	batchOpertValidator.validate(batchOpert, bindingResult);
	if (bindingResult.hasErrors()) {
		return "egovframework/com/sym/bat/EgovBatchOpertRegist";
	} else {
		batchOpert.setBatchOpertId(idgenService.getNextStringId());
		//아이디 설정
		batchOpert.setLastUpdusrId(loginVO == null ? "" : EgovStringUtil.isNullToString(loginVO.getUniqId()));
		batchOpert.setFrstRegisterId(loginVO == null ? "" : EgovStringUtil.isNullToString(loginVO.getUniqId()));

		egovBatchOpertService.insertBatchOpert(batchOpert);
		//Exception 없이 진행시 등록성공메시지
		model.addAttribute("resultMsg", "success.common.insert");
	}
	return "forward:/sym/bat/getBatchOpertList.do";
}

